import React, { useState, useMemo } from 'react';
import { transactions, categoryColors } from '../data/mockData';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(value);

const ITEMS_PER_PAGE = 20;

const categories = ['All', ...new Set(transactions.map(t => t.category))];

export default function Transactions() {
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('All');
  const [sortBy, setSortBy] = useState('date');
  const [sortDir, setSortDir] = useState('desc');
  const [page, setPage] = useState(1);

  const filtered = useMemo(() => {
    let result = transactions;

    if (search) {
      const q = search.toLowerCase();
      result = result.filter(t =>
        t.merchant.toLowerCase().includes(q) || t.category.toLowerCase().includes(q)
      );
    }

    if (category !== 'All') {
      result = result.filter(t => t.category === category);
    }

    result = [...result].sort((a, b) => {
      let cmp = 0;
      if (sortBy === 'date') cmp = a.date.localeCompare(b.date);
      else if (sortBy === 'amount') cmp = Math.abs(a.amount) - Math.abs(b.amount);
      else if (sortBy === 'merchant') cmp = a.merchant.localeCompare(b.merchant);
      return sortDir === 'desc' ? -cmp : cmp;
    });

    return result;
  }, [search, category, sortBy, sortDir]);

  const totalPages = Math.ceil(filtered.length / ITEMS_PER_PAGE);
  const paginated = filtered.slice((page - 1) * ITEMS_PER_PAGE, page * ITEMS_PER_PAGE);

  function handleSort(col) {
    if (sortBy === col) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(col);
      setSortDir('desc');
    }
  }

  const sortIcon = (col) => {
    if (sortBy !== col) return '';
    return sortDir === 'asc' ? ' ^' : ' v';
  };

  return (
    <div>
      <div className="page-header">
        <h1>Transactions</h1>
        <p>{filtered.length} transactions found</p>
      </div>

      <div className="filters-bar">
        <input
          type="text"
          className="filter-input"
          placeholder="Search merchants..."
          value={search}
          onChange={e => { setSearch(e.target.value); setPage(1); }}
          style={{ minWidth: 240 }}
        />
        <select
          className="filter-input"
          value={category}
          onChange={e => { setCategory(e.target.value); setPage(1); }}
        >
          {categories.map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>

      <div className="card">
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th onClick={() => handleSort('date')} style={{ cursor: 'pointer' }}>
                  Date{sortIcon('date')}
                </th>
                <th onClick={() => handleSort('merchant')} style={{ cursor: 'pointer' }}>
                  Merchant{sortIcon('merchant')}
                </th>
                <th>Category</th>
                <th onClick={() => handleSort('amount')} style={{ cursor: 'pointer' }}>
                  Amount{sortIcon('amount')}
                </th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {paginated.map(t => (
                <tr key={t.id} style={t.anomaly ? { background: 'rgba(239, 68, 68, 0.05)' } : {}}>
                  <td style={{ color: 'var(--text-secondary)' }}>{t.date}</td>
                  <td>
                    {t.merchant}
                    {t.anomaly && (
                      <span style={{
                        marginLeft: 8,
                        fontSize: 11,
                        fontWeight: 700,
                        color: 'var(--red)',
                        background: 'rgba(239, 68, 68, 0.15)',
                        padding: '2px 6px',
                        borderRadius: 4
                      }}>
                        ANOMALY
                      </span>
                    )}
                  </td>
                  <td>
                    <span
                      className="category-tag"
                      style={{
                        borderLeft: `3px solid ${categoryColors[t.category] || '#6b7280'}`,
                        paddingLeft: 8
                      }}
                    >
                      {t.category}
                    </span>
                  </td>
                  <td className={t.amount >= 0 ? 'amount-positive' : 'amount-negative'}>
                    {t.amount >= 0 ? '+' : ''}{formatCurrency(t.amount)}
                  </td>
                  <td>
                    {t.pending
                      ? <span className="pending-tag">Pending</span>
                      : <span style={{ color: 'var(--text-muted)', fontSize: 13 }}>Cleared</span>
                    }
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {totalPages > 1 && (
          <div className="pagination">
            <button className="page-btn" disabled={page === 1} onClick={() => setPage(p => p - 1)}>
              &lt;
            </button>
            {Array.from({ length: Math.min(totalPages, 7) }, (_, i) => {
              let pageNum;
              if (totalPages <= 7) {
                pageNum = i + 1;
              } else if (page <= 4) {
                pageNum = i + 1;
              } else if (page >= totalPages - 3) {
                pageNum = totalPages - 6 + i;
              } else {
                pageNum = page - 3 + i;
              }
              return (
                <button
                  key={pageNum}
                  className={`page-btn ${page === pageNum ? 'active' : ''}`}
                  onClick={() => setPage(pageNum)}
                >
                  {pageNum}
                </button>
              );
            })}
            <button className="page-btn" disabled={page === totalPages} onClick={() => setPage(p => p + 1)}>
              &gt;
            </button>
          </div>
        )}
      </div>
    </div>
  );
}
